from sympy import factorint
def a(n):
    fact = factorint(n)
    prod = 1
    for p, k in fact.items():
        if p == 5 and k != 1: return 0
        if p % 5 in [1, 4] and p != 5: prod *= 2
        elif p == 5: continue
        else: return 0
    return prod # _Do Thanh Nhan_, Apr 18 2026

